// 카카오 i 오픈빌더 스킬 요청 파싱
const body = $json.body || {};
const utter = (body.userRequest?.utterance || '').trim();
const userId = body.userRequest?.user?.id || '';
// 간단 인텐트 분기 (실서비스에서는 오픈빌더 블록/엔티티 또는 AI로 분류)
let intent = 'fallback';
if (/견적|비용|가격|얼마/.test(utter)) intent = 'estimate';
else if (/상담|문의|예약|실측/.test(utter)) intent = 'consult';
else if (/사례|포트폴리오|시공/.test(utter)) intent = 'portfolio';
else if (/A\/?S|하자|보수/i.test(utter)) intent = 'as';
return [{ json: { utter, userId, intent } }];

// 인텐트별 카카오 응답 템플릿(2.0) 생성
const { intent, utter } = $json;
const HOME = 'https://your-site.example.com';
const reply = {
  estimate: '평수·공사범위를 알려주시면 참고 예상 범위를 안내드려요. 웹에서 30초 견적도 가능합니다 👇\n' + HOME + '/#estimator\n(최종 금액은 현장 실측 후 확정됩니다.)',
  consult: '상담 신청 감사합니다! 아래에서 단계별 정보를 남겨주시면 대표 검토 후 카카오톡으로 회신드립니다 👇\n' + HOME + '/#inquiry',
  portfolio: '지역·평수·예산으로 유사 시공사례를 골라보실 수 있어요 👇\n' + HOME + '/#portfolio',
  as: 'A/S 접수는 사진과 함께 남겨주시면 빠르게 배정해드립니다. 상담 채널로 사진을 보내주세요.',
  fallback: '안녕하세요! 만물인테리어 챗봇입니다 🤖\n무엇을 도와드릴까요? 아래에서 선택해주세요.'
};
const text = reply[intent] || reply.fallback;
const kakao = {
  version: '2.0',
  template: {
    outputs: [ { simpleText: { text } } ],
    quickReplies: [
      { label: '30초 견적', action: 'message', messageText: '견적 알려줘' },
      { label: '상담 신청', action: 'message', messageText: '상담하고 싶어요' },
      { label: '시공사례', action: 'message', messageText: '시공사례 보여줘' },
      { label: 'A/S 문의', action: 'message', messageText: 'A/S 접수' }
    ]
  }
};
return [{ json: kakao }];
